async (params, browser) => {
  // Open Figma file
  await browser.open(`${params.file_url}`)

  // Wait for editor to load
  await browser.waitForSelector('[class*="layers_panel"], .layers-panel, [class*="toolbar"], [data-testid="canvas"]', 20000)

  // Let canvas and panels render
  await browser.wait(4000)

  // Extract file details and layer info
  const result = await browser.evaluate(`const fileName = document.querySelector('[class*="filename"], [data-testid="filename"], [class*="file_name"], .toolbar-title input, [class*="toolbar"] [class*="name"]')?.textContent?.trim() || document.title.replace(' - Figma', '').trim() || ''; const pages = []; const pageItems = document.querySelectorAll('.page_item, [class*="page_row"], [class*="pages_panel"] [class*="page_name"], [data-testid="page-name"]'); pageItems.forEach(p => { pages.push(p.textContent.trim()); }); const layerItems = document.querySelectorAll('[class*="layers_panel"] [class*="layer_row"], [class*="object_row"], [class*="layers-panel"] [class*="item"]'); let frameCount = 0; let componentCount = 0; layerItems.forEach(item => { const iconEl = item.querySelector('[class*="icon"], svg'); const text = iconEl ? iconEl.getAttribute('class') || '' : ''; if (text.includes('frame') || text.includes('Frame')) frameCount++; if (text.includes('component') || text.includes('Component')) componentCount++; }); const totalLayers = layerItems.length; return { file_name: fileName, url: window.location.href, page_count: pages.length, pages: pages, total_layers_visible: totalLayers, frame_count: frameCount, component_count: componentCount }`)

  return result
}
